import os
import requests
from flask import Flask, redirect, url_for, session, request

app = Flask(__name__)
app.secret_key = os.urandom(24)  # Replace with a strong, permanent key in production

# OAuth 2.0 Client Configuration
CLIENT_ID = 'your_client_id'  # Replace with your actual client ID
CLIENT_SECRET = 'your_client_secret'  # Replace with your actual client secret
AUTHORIZATION_BASE_URL = 'http://localhost:5000/oauth/authorize'  # Replace with auth server's auth endpoint
TOKEN_URL = 'http://localhost:5000/oauth/token'  # Replace with auth server's token endpoint
REDIRECT_URI = 'http://localhost:5001/callback'  # Must match the redirect URI registered with the auth server
SCOPE = 'profile email'  # Define the scopes your application needs

@app.route('/')
def index():
    if 'access_token' in session:
        return f"Hello, you are logged in! Access Token: {session['access_token']}<br><a href='/logout'>Logout</a>"
    return '<a href="/login">Login with OAuth 2.0</a>'

@app.route('/login')
def login():
    # Redirect user to the authorization server
    params = {
        'response_type': 'code',
        'client_id': CLIENT_ID,
        'redirect_uri': REDIRECT_URI,
        'scope': SCOPE,
        'state': os.urandom(16).hex() # Recommended to prevent CSRF
    }
    session['oauth_state'] = params['state'] # Store state to verify in callback
    auth_url = f"{AUTHORIZATION_BASE_URL}?{'&'.join([f'{k}={v}' for k, v in params.items()])}"
    return redirect(auth_url)

@app.route('/callback')
def callback():
    error = request.args.get('error')
    if error:
        return f"OAuth Error: {error} - {request.args.get('error_description') or ''}"

    code = request.args.get('code')
    state_from_server = request.args.get('state')

    # Verify state to prevent CSRF
    if not code or not state_from_server or state_from_server != session.pop('oauth_state', None):
        return "State mismatch or missing code", 400

    # Exchange authorization code for an access token
    token_payload = {
        'grant_type': 'authorization_code',
        'code': code,
        'redirect_uri': REDIRECT_URI,
        'client_id': CLIENT_ID,
        'client_secret': CLIENT_SECRET,
    }

    try:
        response = requests.post(TOKEN_URL, data=token_payload)
        response.raise_for_status()  # Raise an exception for HTTP errors
        token_data = response.json()

        access_token = token_data.get('access_token')
        if access_token:
            session['access_token'] = access_token
            # You might want to store other token data like refresh_token, expires_in, etc.
            return redirect(url_for('index'))
        else:
            return f"Failed to get access token: {token_data}", 500

    except requests.exceptions.RequestException as e:
        return f"Error exchanging code for token: {e}", 500
    except ValueError:
        return "Error decoding token response from authorization server", 500

@app.route('/logout')
def logout():
    session.pop('access_token', None)
    session.pop('oauth_state', None)
    return redirect(url_for('index'))

if __name__ == '__main__':
    # Ensure to run this client app on a different port than the authorization server
    # For example, if the auth server is on 5000, run this on 5001
    app.run(debug=True, port=5001)